using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup() => _cart = new ShoppingCart();

    // ── AddItem ──────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_AppearsInCart()
    {
        _cart.AddItem("SKU-1", 2, 9.99m);

        Assert.AreEqual(2, _cart.Items["SKU-1"].Quantity);
        Assert.AreEqual(9.99m, _cart.Items["SKU-1"].Price);
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_QuantitiesAreSummed()
    {
        _cart.AddItem("SKU-1", 1, 5.00m);
        _cart.AddItem("SKU-1", 3, 5.00m);

        Assert.AreEqual(4, _cart.Items["SKU-1"].Quantity);
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_AllAppear()
    {
        _cart.AddItem("A", 1, 1.00m);
        _cart.AddItem("B", 2, 2.00m);
        _cart.AddItem("C", 3, 3.00m);

        Assert.HasCount(_cart.Items, 3);
    }

    [TestMethod]
    public void AddItem_NullSku_Throws() =>
        Assert.Throws<ArgumentException>(() => _cart.AddItem(null!, 1, 1.00m));

    [TestMethod]
    public void AddItem_EmptySku_Throws() =>
        Assert.Throws<ArgumentException>(() => _cart.AddItem("", 1, 1.00m));

    [TestMethod]
    public void AddItem_WhitespaceSku_Throws() =>
        Assert.Throws<ArgumentException>(() => _cart.AddItem("   ", 1, 1.00m));

    [TestMethod]
    public void AddItem_ZeroQuantity_Throws() =>
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(() => _cart.AddItem("SKU-1", 0, 1.00m));

    [TestMethod]
    public void AddItem_NegativeQuantity_Throws() =>
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(() => _cart.AddItem("SKU-1", -1, 1.00m));

    [TestMethod]
    public void AddItem_NegativePrice_Throws() =>
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(() => _cart.AddItem("SKU-1", 1, -5.00m));

    [TestMethod]
    public void AddItem_ZeroPrice_Succeeds()
    {
        _cart.AddItem("FREEBIE", 1, 0.00m);

        Assert.AreEqual(0.00m, _cart.Items["FREEBIE"].Price);
    }

    // ── RemoveItem ───────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovedFromCart()
    {
        _cart.AddItem("SKU-1", 1, 10.00m);
        _cart.RemoveItem("SKU-1");

        Assert.IsEmpty(_cart.Items);
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_Throws() =>
        Assert.ThrowsExactly<InvalidOperationException>(() => _cart.RemoveItem("MISSING"));

    [TestMethod]
    public void RemoveItem_NullSku_Throws() =>
        Assert.Throws<ArgumentException>(() => _cart.RemoveItem(null!));

    [TestMethod]
    public void RemoveItem_OnlyTargetRemoved_OtherItemsRemain()
    {
        _cart.AddItem("A", 1, 1.00m);
        _cart.AddItem("B", 1, 2.00m);
        _cart.RemoveItem("A");

        Assert.HasCount(_cart.Items, 1);
        Assert.IsTrue(_cart.Items.ContainsKey("B"));
    }

    // ── CalculateTotal ───────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsCorrectTotal()
    {
        _cart.AddItem("SKU-1", 3, 4.50m);

        Assert.AreEqual(13.50m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_SumsCorrectly()
    {
        _cart.AddItem("A", 2, 10.00m); // 20.00
        _cart.AddItem("B", 1, 5.50m);  //  5.50

        Assert.AreEqual(25.50m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterRemoval_ExcludesRemovedItem()
    {
        _cart.AddItem("A", 1, 100.00m);
        _cart.AddItem("B", 1, 50.00m);
        _cart.RemoveItem("A");

        Assert.AreEqual(50.00m, _cart.CalculateTotal());
    }

    // ── ApplyCoupon ──────────────────────────────────────────

    [TestMethod]
    public void ApplyCoupon_Save10_Applies10PercentDiscount()
    {
        _cart.AddItem("SKU-1", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");

        Assert.AreEqual(90.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_Save20_Applies20PercentDiscount()
    {
        _cart.AddItem("SKU-1", 1, 100.00m);
        _cart.ApplyCoupon("SAVE20");

        Assert.AreEqual(80.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_Half_Applies50PercentDiscount()
    {
        _cart.AddItem("SKU-1", 1, 100.00m);
        _cart.ApplyCoupon("HALF");

        Assert.AreEqual(50.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_CaseInsensitive()
    {
        _cart.AddItem("SKU-1", 1, 200.00m);
        _cart.ApplyCoupon("save10");

        Assert.AreEqual(180.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_UnknownCode_Throws() =>
        Assert.ThrowsExactly<ArgumentException>(() => _cart.ApplyCoupon("BOGUS"));

    [TestMethod]
    public void ApplyCoupon_NullCode_Throws() =>
        Assert.Throws<ArgumentException>(() => _cart.ApplyCoupon(null!));

    [TestMethod]
    public void ApplyCoupon_EmptyCode_Throws() =>
        Assert.Throws<ArgumentException>(() => _cart.ApplyCoupon(""));

    [TestMethod]
    public void ApplyCoupon_ReplacedByNewCoupon_UsesLatest()
    {
        _cart.AddItem("SKU-1", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");
        _cart.ApplyCoupon("SAVE20");

        Assert.AreEqual(80.00m, _cart.CalculateTotal());
    }

    // ── Rounding ─────────────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_WithCoupon_RoundsToTwoDecimals()
    {
        _cart.AddItem("SKU-1", 3, 9.99m); // subtotal = 29.97
        _cart.ApplyCoupon("SAVE10");       // 29.97 * 0.90 = 26.973

        Assert.AreEqual(26.97m, _cart.CalculateTotal());
    }

    // ── End-to-end scenario ──────────────────────────────────

    [TestMethod]
    public void FullWorkflow_AddRemoveCouponTotal()
    {
        _cart.AddItem("WIDGET", 4, 12.50m);  // 50.00
        _cart.AddItem("GADGET", 1, 24.99m);  // 24.99
        _cart.AddItem("DONGLE", 2, 7.00m);   // 14.00
        _cart.RemoveItem("DONGLE");
        _cart.ApplyCoupon("SAVE20");

        // (50.00 + 24.99) * 0.80 = 59.992 → 59.99
        Assert.AreEqual(59.99m, _cart.CalculateTotal());
    }
}

